def _majority_vote(image_id: str, min_total: int = DEFAULT_MIN_LABELS_TO_AGGREGATE) -> Optional[Dict[str, Any]]:
    with _db_lock:
        con = _connect()
        rows = con.execute(
            "SELECT label, COUNT(*) as c FROM labels WHERE image_id=? GROUP BY label ORDER BY c DESC, label ASC",
            (image_id,),
        ).fetchall()
        total_row = con.execute(
            "SELECT COUNT(*) as t FROM labels WHERE image_id=?",
            (image_id,),
        ).fetchone()
        total = int(total_row["t"]) if total_row else 0
        if total < max(1, int(min_total)):
            con.close()
            return None
        if not rows:
            con.close()
            return None
        top_label = rows[0]["label"]
        top_votes = int(rows[0]["c"])
        tied = [r for r in rows if int(r["c"]) == top_votes]
        if len(tied) > 1:
            con.close()
            return None
        con.execute(
            """
            INSERT INTO aggregated_labels (image_id, label, votes, total, updated_at)
            VALUES (?,?,?,?,?)
            ON CONFLICT(image_id) DO UPDATE SET
                label=excluded.label,
                votes=excluded.votes,
                total=excluded.total,
                updated_at=excluded.updated_at
            """,
            (image_id, top_label, top_votes, total, _now_ts()),
        )
        con.commit()
        con.close()
    return {"image_id": image_id, "label": top_label, "votes": top_votes, "total": total}


